/**
 * Provides a utility function to determine whether a graphic's origin is a [MapNotesGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/MapNotesGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a MapNotesLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isMapNotesGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a MapNotesLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a MapNotesLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type MapNotesGraphicOrigin from "./MapNotesGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [MapNotesGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/MapNotesGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [MapNotesGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/MapNotesGraphicOrigin/), `false` otherwise.
 */
export function isMapNotesGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is MapNotesGraphicOrigin;